import type { Tree } from '@lezer/common';

import type {
  FilterFieldLeafNode,
  FilterFieldStatementTokenType,
  FilterFieldTree,
  FilterFieldValueNode,
} from '../../types/tree-nodes.js';
import {
  isFilterFieldLeafNode,
  isFilterFieldListNode,
  isFilterFieldValueNode,
} from '../tree-node-guards.js';
import { getFilterStatement } from './suggestions-callback.js';

/**
 * Get the current token and token type for the given cursor position.
 * @internal
 */
export function getCurrentToken({
  tree,
  convertedTree,
  cursorPosition,
  doc,
}: {
  tree: Tree;
  convertedTree: FilterFieldTree;
  cursorPosition: number;
  doc: string;
}): {
  currentToken: FilterFieldValueNode;
  currentTokenType?: FilterFieldStatementTokenType;
} {
  const fallbackToken: FilterFieldLeafNode = {
    type: 'String',
    textValue: '',
    value: '',
    range: {
      from: cursorPosition,
      to: cursorPosition,
    },
  };

  let currentToken: FilterFieldValueNode = fallbackToken;
  let currentTokenType: FilterFieldStatementTokenType | undefined = undefined;

  const currentStatement = getFilterStatement(
    convertedTree,
    cursorPosition,
    doc,
  );

  const treeCursor = tree.cursorAt(cursorPosition, -1);

  if (!currentStatement) {
    if (treeCursor.node.name === 'LogicalOperator') {
      currentToken =
        (convertedTree?.children.find(
          (token) =>
            isFilterFieldValueNode(token) &&
            token.range.from <= cursorPosition &&
            token.range.to >= cursorPosition,
        ) as FilterFieldValueNode) ?? fallbackToken;
    }
  } else {
    for (const [key, value] of Object.entries(currentStatement)) {
      if (
        isFilterFieldValueNode(value) &&
        value.range.from <= cursorPosition &&
        value.range.to >= cursorPosition
      ) {
        currentToken = value as FilterFieldValueNode;
        currentTokenType = key as FilterFieldStatementTokenType;
        break;
      }
    }
  }

  if (
    Array.isArray(currentToken.value) &&
    isFilterFieldListNode(currentToken)
  ) {
    currentToken =
      (currentToken.value?.find(
        (token) =>
          isFilterFieldLeafNode(token) &&
          token.range.from <= cursorPosition &&
          token.range.to >= cursorPosition,
      ) as FilterFieldValueNode) ?? currentToken;

    // If the current token is still the list or error, no value nodes exists yet.
    // Depending on the cursor position, we return either the fallback token or the
    // currentToken.
    /* Examples:
        - a in |()    -> return list token, whole list will be replaced.
        - a in |(     -> return error token, whole error will be replaced.
        - a in (|)    -> return fallback token, suggestion will be added to the list.
        - a in (|     -> return fallback token, suggestion will be added to the list.
        - a in (a, |  -> return fallback token, suggestion will be added to the list.
        - a in (a, |) -> return fallback token, suggestion will be added to the list.
        - a in (a, )| -> return error token, whole error will be replaced.
      */
    if (currentToken.type === 'List' || currentToken.type === 'Error') {
      let nodeCursor = tree.cursorAt(cursorPosition, 1);
      if (nodeCursor.node.name === 'Filter') {
        nodeCursor = tree.cursorAt(cursorPosition, -1);
      }

      const { node } = nodeCursor.node;

      // If the node at the cursor position is one of the following, we don't
      // want to return the whole token, but only the fallback token.
      // `ClosingBracket` is excluded, since the token then also depends on the cursor position.
      const tokensInsideList = [
        'List',
        'Identifier',
        'String',
        'Boolean',
        'Number',
        'Duration',
      ];

      if (
        tokensInsideList.includes(node.name) ||
        (node.name === 'OpeningBracket' && cursorPosition > node.from) ||
        (node.name === 'ClosingBracket' && cursorPosition < node.to)
      ) {
        currentToken = fallbackToken;
      }
    }
  }

  return { currentToken, currentTokenType };
}
